//---------------------------------------------------------
// function name : f_set
// function desc : 화면 open시 초기 데이타 setting
//---------------------------------------------------------
scwin.f_set = function (gubun) {
    switch (gubun) {
        case "ONLOAD":
            $c.gus.cfDisableKey()

            ed_cnd_ed_bkEtdFrom.setValue(scwin.strPreDate)
            ed_cnd_ed_bkEtdTo.setValue(scwin.strCurDate)

            rd_cnd_rd_bkbltype.setValue("")

            ed_cnd_ed_bkNo.focus()
            break

        case "RETRIEVE":
            $c.gus.cfEnableAllBtn()
            break;

        case "DELETE":
            $c.gus.cfDisableBtn();
            break;
    }
};

//-------------------------------------------------------------------------
// function name : f_DefaultValue
// function desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    lc_iogb.setSelectedIndex(0)
};



// 조회 완료
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code != 0) {
		return;
	}

	// 그리드 조회건수 초기화
	if (ds_bookingList.getRowCount() > 0) {
		tbx_totalRows.setValue(ds_bookingList.getRowCount())// 조회된 건수를 매출입항목Grid 하단에 표시한다.		
		scwin.f_set("RETRIEVE");
	} else {
		$c.win.alert(E_MSG_CM_WRN_002);
	}
};


//---------------------------------------------------------
// 조회 조건 지우기
//---------------------------------------------------------
scwin.f_FieldClear = function (e) {
    $c.gus.cfInitObjects(tbl_searchCondition); // 조회조건의 테이블을 초기화.
    scwin.f_set("ONLOAD");
};

//---------------------------------------------------------
// 조회
//---------------------------------------------------------    
scwin.f_Retrieve = async function (e) {

	let rtn = await scwin.f_validate();
    if (rtn) {

		ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
		ds_retrieve.set("flag", 0);

		$c.sbm.execute(sbm_retrieve);
    }
};

//---------------------------------------------------------
// function name : f_validate
// function desc : 
//---------------------------------------------------------
scwin.f_validate = async function () {

    // VALIDATE
    let ret = await $c.gus.cfValidate([ed_cnd_ed_bkEtdFrom, ed_cnd_ed_bkEtdTo])
    if (!ret) {  //validExp 가 yes일때 check
        return false
    }

    if (ed_cnd_ed_bkEtdFrom.getValue() == "") {
        $c.win.alert($c.data.getMessage(E_MSG_CM_ERR_002, "ETD From")); //@는 필수입력항목입니다.
        ed_cnd_ed_bkEtdFrom.focus();
        return false;
    }
    if (ed_cnd_ed_bkEtdTo.getValue() == "") {
        $c.win.alert($c.data.getMessage(E_MSG_CM_ERR_002, "ETD To")); //@는 필수입력항목입니다.
        ed_cnd_ed_bkEtdTo.focus();
        return false;
    }

    // 날짜 범위 확인
    if (!$c.gus.cfIsAfterDate(ed_cnd_ed_bkEtdFrom.getValue(), ed_cnd_ed_bkEtdTo.getValue())) {
        $c.win.alert($c.data.getMessage(E_MSG_CM_ERR_048, "ETD From", "ETD To"));  //@은(는) 보다 작아야 합니다.
        ed_cnd_ed_bkEtdFrom.focus();
        return false;
    }

    return true;
};

