                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Vessel,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Discharge":
            udc_disCd.setSelectId('retrievePortInfo')
            udc_disCd.ilCommonPopUp(scwin.udc_disCd_callBackFunc
                , ed_cnd_ed_disCd.getValue().trim()
                , ""
                , pWinCloseTF
                , '6'
                , 'Code, Name,,,, UNCODE'
                , '80,160,,,,80'
                , "3,4,5,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Discharge,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Factory":
            udc_factCd.setSelectId('retrievePortInfo')
            udc_factCd.ilCommonPopUp(scwin.udc_factCd_callBackFunc
                , ed_cnd_ed_factCd.getValue().trim()
                , ""
                , pWinCloseTF
                , '6'
                , 'Code, Name,,,, UNCODE'
                , '80,160,,,,80'
                , "3,4,5,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Factory,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Loading":
            udc_lodCd.setSelectId('retrievePortInfo')
            udc_lodCd.ilCommonPopUp(scwin.udc_lodCd_callBackFunc
                , ed_cnd_ed_lodCd.getValue().trim()
                , ""
                , pWinCloseTF
                , '6'
                , 'Code, Name,,,, UNCODE'
                , '80,160,,,,80'
                , "3,4,5,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Loading,Code,Name"
                , pNoDataCloseTF
            );
            break;
        case "Item":
            udc_itemCd.setSelectId('retrieveCommGoodsInfo')
            udc_itemCd.ilCommonPopUp(scwin.udc_itemCd_callBackFunc
                , ed_cnd_ed_itemCd.getValue().trim()
                , ""
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Item,Code,Name"
                , pNoDataCloseTF
            );
            break;
        case "Salesman":
            udc_salesCd.setSelectId('retrieveEmpInfo')
            udc_salesCd.ilCommonPopUp(scwin.udc_salesCd_callBackFunc
                , ed_cnd_ed_salesCd.getValue().trim()
                , ed_cnd_txt_salesNm.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Salesman,Code,Name"
                , pNoDataCloseTF
            );
            break;
    }

};



//---------------------------------------------------------
// 엑셀다운로드
//---------------------------------------------------------
scwin.f_downExcelSheet = async function () {

    let cntRow = ds_bookingList.getRowCount()
    if (cntRow < 1) { 
		await $c.win.alert(E_MSG_CM_WRN_002);
		return;
	}

	let cfrm = await $c.win.confirm("House B/L List를 EXCEL로 다운로드 받으시겠습니까?");

	if (!cfrm) {
		return;
	}

	const options = {
            fileName : "Booking List.xlsx", 
            sheetName: "Booking List"
        };

	$c.data.downloadGridViewExcel(gr_bookingList, options, {});
};


scwin.displayWgt = function (data) {
    //data 에서 소숫점을 기준으로 나눠서 앞자리와 뒷자리를 분리한다.
	let index = data.indexOf(".");
	if(index == -1) { //소수점이 없는 경우
		return data.replace(/\B(?=(\d{3})+(?!\d))/g, ","); //정수 부분에 3자리마다 콤마를 찍어서 반환한다.
	}	

	let intPart = data.substring(0, index); //정수 부분	
	let decimalPart = data.substring(index + 1); //소수 부분

	//정수 부분은 3자리마다 콤마를 찍어준다.
	intPart = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, ",");

	return intPart + "." + decimalPart;	
};

scwin.displayBkbltype = function (data) {
        //data 에서 소숫점을 기준으로 나눠서 앞자리와 뒷자리를 분리한다.
	let index = data.indexOf(".");
	if(index == -1) { //소수점이 없는 경우
		return data.replace(/\B(?=(\d{3})+(?!\d))/g, ","); //정수 부분에 3자리마다 콤마를 찍어서 반환한다.
	}	

	let intPart = data.substring(0, index); //정수 부분	
	let decimalPart = data.substring(index + 1); //소수 부분

	//정수 부분은 3자리마다 콤마를 찍어준다.
	intPart = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
	//소수부분은 최대 3자리까지 표시하고 마지막이 0이면 0이 없어질때까지 제거한다.
	decimalPart = decimalPart.substring(0, 3);
	while(decimalPart.endsWith("0")) {
		decimalPart = decimalPart.substring(0, decimalPart.length - 1);
	}

	return intPart + "." + decimalPart;	
};


